def strip_selected():
    """Strip selected categories/tags and return cleaned image."""
    if "file" not in request.files:
        return jsonify({"status": "error"}), 400

    f = request.files["file"]
    raw_bytes = f.read()

    data = request.get_json(silent=True) or {}
    cats_to_remove = set(data.get("categories", []))
    tags_to_remove_ids = set(data.get("tags", []))  # specific tag IDs to remove

    try:
        import piexif
        exif_dict = piexif.load(raw_bytes)
    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500

    for ifd_name in list(exif_dict.keys()):
        td = exif_dict[ifd_name]
        if not isinstance(td, dict):
            continue
        tags_to_del = []
        try:
            tag_info_map = piexif.TAGS.get(ifd_name, {})
        except Exception:
            tag_info_map = {}

        for tid in td.keys():
            label = "Unknown"
            ti = tag_info_map.get(tid)
            if ti and len(ti) > 0:
                label = str(ti[0])
            cat = _classify_tag(label.split("/")[-1].strip() if "/" in label else label.strip())

            if cat in cats_to_remove or str(tid) in tags_to_remove_ids:
                tags_to_del.append(int(str(tid)))

        for tid_int in tags_to_del:
            to_delete = [k for k in td.keys() if int(k) == int(tid_int)]
            for dk in to_delete:
                del exif_dict[ifd_name][dk]

    if "Location (GPS)" in cats_to_remove and isinstance(exif_dict.get("GPS"), dict):
        exif_dict["GPS"] = {}

    try:
        new_raw = piexif.insert(piexif.dump(exif_dict), raw_bytes)
    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500

    base_ext = os.path.splitext(f.filename.lower())[1].lstrip(".") or "jpg"
    safe_name = f'scrubbed_{f.filename}' if f.filename else "scrubbed_image.jpg"

    return send_file(
        io.BytesIO(new_raw),
        mimetype=f'image/{base_ext}',
        as_attachment=True,
        download_name=safe_name,
    )


@app.route("/api/compare", methods=["POST"])
def compare_metadata():
    """Upload original + scrubbed image and return both metadata sets for comparison."""
    if "original" not in request.files or "scrubbed" not in request.files:
        return jsonify({"status": "error", "message": "Need both 'original' and 'scrubbed' files"}), 400

    orig_bytes = request.files["original"].read()
    scrub_bytes = request.files["scrubbed"].read()

    try:
        import piexif
        orig_exif = piexif.load(orig_bytes)
    except Exception:
        orig_exif = {}

    try:
        import piexif
        scrub_exif = piexif.load(scrub_bytes)
    except Exception:
        scrub_exif = {}

    def _build_meta(exif_d):
        meta = []
        for ifd_name, tag_data in (exif_d or {}).items():
            friendly = _friendly_group(ifd_name)
            for tid, raw_val in tag_data.items():
                try:
                    tag_info_map = piexif.TAGS.get(ifd_name, {})
                    label = str(tag_info_map.get(tid, ("Unknown",))[0]) if tag_info_map else "Unknown"
                except Exception:
                    label = "Unknown"
                meta.append({
                    "group": friendly,
                    "tag": label,
                    "value": _decode_value(raw_val),
                    "category": _classify_tag(label),
                })
        return meta

    return jsonify({
        "status": "ok",
        "before": _build_meta(orig_exif),
        "after": _build_meta(scrub_exif),
        "before_count": sum(len(v) for v in (orig_exif or {}).values()),
        "after_count": sum(len(v) for v in (scrub_exif or {}).values()),
    })


