<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>ImageScrub — Metadata Scrubber &amp; Viewer</title>
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link href="https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700&family=Rajdhani:wght@300;400;500;600;700&display=swap" rel="stylesheet">

  <!-- ===================== CSS ===================== -->
  <style>
    :root {
      --bg:        #0a0a12;
      --surface:   rgba(14,18,32,.85);
      --card:      rgba(20,26,46,.9);
      --accent:    #50fff0;
      --accent2:   #9c0aef;
      --danger:    #ff4070;
      --warn:      #ffb830;
      --ok:        #30e670;
      --text:      #e0e6f0;
      --muted:     #7a8ba8;
      --radius:    16px;
      --glow:      0 0 24px rgba(80,255,240,.35);
    }

    * { margin:0; padding:0; box-sizing:border-box; }

    body {
      background: var(--bg);
      color: var(--text);
      font-family: 'Rajdhani', sans-serif;
      min-height: 100vh;
      overflow-x: hidden;
    }

    /* Scanline overlay */
    .scanline {
      position:fixed; top:0; left:0; width:100%; height:100%;
      pointer-events:none; z-index:9999;
      background: repeating-linear-gradient(0deg, transparent 0px, rgba(80,255,240,.025) 2px, transparent 4px);
    }

    /* ── Header ── */
    header { text-align:center; padding:5vh 1rem 2vh; position:relative; }
    h1 {
      font-family:'Orbitron',sans-serif; font-size:clamp(2rem,5vw,3.6em);
      color:var(--accent);
      text-shadow: 0 0 40px rgba(80,255,240,.5), inset 0 0 12px rgba(80,255,240,.08);
    }
    header .sub { color:var(--muted); font-size:1.15rem; margin-top:.6vh; letter-spacing:.22em; text-transform:uppercase; }

    /* ── Main Container ── */
    main {
      max-width:960px; min-height:60vh; background:var(--surface);
      border-radius:var(--radius); padding:2.5rem; margin-inline:auto;
      box-shadow: 0 8px 40px rgba(0,0,0,.5);
    }

    /* ── Drop Zone ── */
    .drop-zone {
      border:2.5px dashed var(--accent2); border-radius:var(--radius);
      text-align:center; cursor:pointer; padding:4rem 2rem;
      transition:.2s ease; position:relative;
    }
    .drop-zone:hover, .drop-zone.drag-over {
      background:rgba(156,10,239,.08);
      box-shadow:inset 0 0 40px rgba(156,10,239,.12);
    }
    .drop-zone p { font-size:1.3rem; color:var(--muted); margin-top:.8rem; }
    .drop-zone .icon { font-size:3.5rem; margin-bottom:.4rem; }

    #fileInput { display:none; }

    /* ── Sections (hidden until image loaded) ── */
    .section { display:none; margin-top:2rem; animation: fadeUp .4s ease; }
    .section.visible { display:block; }
    @keyframes fadeUp { from{opacity:0;transform:translateY(18px)} to{opacity:1;transform:none} }

    .section-title {
      font-family:'Orbitron',sans-serif; font-size:1.4rem; color:var(--accent);
      margin-bottom:1rem; display:flex; align-items:center; gap:.6rem;
    }
    .section-title .badge {
      background:rgba(80,255,240,.12); color:var(--accent); font-size:.75rem;
      padding:.15em .6em; border-radius:99px; font-family:'Rajdhani';
    }

    /* ── Image Preview ── */
    .preview-row { display:flex; gap:1.2rem; flex-wrap:wrap; align-items:flex-start; }
    .preview-card {
      flex:1 1 300px; background:var(--card); border-radius:12px; padding:1rem; text-align:center;
    }
    .preview-card img { max-width:100%; max-height:320px; border-radius:8px; object-fit:contain; }
    .preview-card h3 { margin:.6rem 0 .2rem; color:var(--accent); font-size:1rem; }
    .preview-card .dim { color:var(--muted); font-size:.95rem; }

    /* ── Metadata Table ── */
    .meta-table-wrap { max-height:420px; overflow-y:auto; border-radius:12px; background:var(--card); }
    .meta-table { width:100%; border-collapse:collapse; font-size:.95rem; }
    .meta-table th {
      position:sticky; top:0; background:#141a2e; z-index:2;
      text-align:left; padding:.7rem 1rem; color:var(--accent); font-weight:600;
      border-bottom:1px solid rgba(80,255,240,.15);
    }
    .meta-table td { padding:.55rem 1rem; border-bottom:1px solid rgba(255,255,255,.04); }
    .meta-table tr:hover td { background:rgba(80,255,240,.03); }
    .cat-badge {
      display:inline-block; padding:.1em .55em; border-radius:99px; font-size:.78rem; font-weight:600;
    }
    .cat-Camera { background:rgba(156,10,239,.18); color:#d4a0ff; }
    .cat-Location { background:rgba(255,64,112,.15); color:#ff709a; }
    .cat-Date { background:rgba(255,184,48,.15); color:#ffd370; }
    .cat-Software { background:rgba(48,230,112,.12); color:#70ffaa; }
    .cat-Other  { background:rgba(122,139,168,.15); color:#a0b0c8; }

    /* ── Category Checkboxes ── */
    .cat-grid { display:flex; flex-wrap:wrap; gap:.8rem; margin:1rem 0; }
    .cat-chip {
      display:flex; align-items:center; gap:.5rem; background:var(--card);
      padding:.6rem 1.2rem; border-radius:99px; cursor:pointer; user-select:none;
      transition:.15s; border:1.5px solid transparent;
    }
    .cat-chip:hover { border-color:rgba(80,255,240,.3); }
    .cat-chip input { accent-color:var(--danger); width:16px; height:16px; cursor:pointer; }
    .cat-chip .label { font-weight:600; font-size:.95rem; }

    /* ── Buttons ── */
    .btn-row { display:flex; flex-wrap:wrap; gap:.8rem; margin-top:1.2rem; }
    .btn {
      font-family:'Rajdhani',sans-serif; font-weight:600; font-size:1rem;
      padding:.7rem 1.6rem; border:none; border-radius:12px; cursor:pointer;
      transition:.15s; display:inline-flex; align-items:center; gap:.45rem;
    }
    .btn-primary { background:var(--accent); color:#0a0a12; }
    .btn-primary:hover { box-shadow:var(--glow); transform:translateY(-1px); }
    .btn-danger  { background:var(--danger); color:#fff; }
    .btn-danger:hover  { box-shadow:0 0 24px rgba(255,64,112,.35); }
    .btn-outline { background:transparent; border:1.5px solid var(--muted); color:var(--muted); }
    .btn-outline:hover { border-color:var(--accent); color:var(--accent); }
    .btn:disabled { opacity:.45; cursor:not-allowed; transform:none !important; box-shadow:none !important; }

    /* ── Comparison Panel ── */
    .compare-grid { display:grid; grid-template-columns:1fr 1fr; gap:1.2rem; }
    .compare-col h4 { color:var(--accent); margin-bottom:.6rem; font-size:1.05rem; }
    .compare-box { background:var(--card); border-radius:12px; padding:1rem; max-height:380px; overflow-y:auto; }
    .compare-stat { display:flex; justify-content:space-between; padding:.4rem 0; border-bottom:1px solid rgba(255,255,255,.04); font-size:.92rem; }
    .removed-tag { color:var(--danger); text-decoration:line-through; opacity:.6; }
    .kept-tag    { color:var(--ok); }

    /* ── Toast / Status ── */
    #toast {
      position:fixed; bottom:2rem; left:50%; transform:translateX(-50%);
      background:var(--card); color:var(--text); padding:.8rem 1.6rem;
      border-radius:12px; font-weight:600; display:none; z-index:10000;
      box-shadow:0 4px 24px rgba(0,0,0,.5);
    }

    /* ── Footer ── */
    footer { text-align:center; color:var(--muted); font-size:.9rem; padding:3vh 0 4vh; }

    /* ── Spinner ── */
    .spinner { display:inline-block; width:18px; height:18px; border:2.5px solid rgba(255,255,255,.2); border-top-color:#fff; border-radius:50%; animation:spin .6s linear infinite; }
    @keyframes spin { to{transform:rotate(360deg)} }

    /* ── Responsive ── */
    @media(max-width:640px){
      main{padding:1.2rem;}
      .compare-grid{grid-template-columns:1fr;}
      h1{font-size:2rem;}
    }
  </style>
</head>

<body>
<div class="scanline"></div>

<header>
  <h1>&lt;ImageScrub&gt;</h1>
  <p class="sub">Metadata &bull; View &bull; Scrub &bull; Compare</p>
</header>

<main id="main">

  <!-- ── Upload / Drop Zone ── -->
  <section id="uploadSection" class="visible">
    <div class="drop-zone" id="dropZone">
      <div class="icon">&#128247;</div>
      <p><strong>Drag &amp; drop an image here</strong></p>
      <p style="font-size:1rem;color:#5a6a80;margin-top:.3rem;">or click to browse files</p>
      <input id="fileInput" type="file" accept="image/*" hidden />
    </div>
  </section>

  <!-- ── Image Preview + Info ── -->
  <section id="previewSection" class="section">
    <div class="section-title">&#128065; Image Preview <span class="badge" id="fmtBadge"></span></div>
    <div class="preview-row">
      <div class="preview-card">
        <img id="thumbOrig" alt="Original" />
        <h3>Original</h3>
        <p class="dim" id="origDim"></p>
      </div>
      <div class="preview-card" id="scrubPreviewCard" style="display:none;">
        <img id="thumbScrubbed" alt="Scrubbed" />
        <h3>Scrubbed</h3>
        <p class="dim" id="scrubDim"></p>
      </div>
    </div>
  </section>

  <!-- ── Metadata Viewer ── -->
  <section id="metaSection" class="section">
    <div class="section-title">&#128203; All Metadata <span class="badge" id="tagCount"></span></div>
    <div class="meta-table-wrap">
      <table class="meta-table" id="metaTable">
        <thead><tr><th style="width:28%">Category</th><th style="width:30%">Tag</th><th>Value</th></tr></thead>
        <tbody id="metaBody"></tbody>
      </table>
    </div>
  </section>

  <!-- ── Scrub Controls ── -->
  <section id="scrubSection" class="section">
    <div class="section-title">&#128736;&#65039; Choose What to Remove</div>
    <p style="color:var(--muted);margin-bottom:.4rem;">Check the categories you want scrubbed, then hit a button below.</p>
    <div class="cat-grid" id="catGrid"></div>
    <div class="btn-row">
      <button class="btn btn-primary" id="btnScrubSelected">&#9889; Scrub Selected</button>
      <button class="btn btn-danger"  id="btnStripAll">&#128465; Strip Everything</button>
      <button class="btn btn-outline" id="btnReset">&#8634; Reset</button>
    </div>
  </section>

  <!-- ── Before / After Comparison ── -->
  <section id="compareSection" class="section">
    <div class="section-title">&#128270; Before &amp; After Comparison</div>
    <div style="display:flex;gap:1rem;margin-bottom:1rem;">
      <div style="flex:1;text-align:center;background:var(--card);padding:.8rem;border-radius:12px;">
        <div style="font-size:2rem;font-weight:700;color:var(--accent);" id="beforeCount">0</div>
        <div style="color:var(--muted);font-size:.85rem;">Tags Before</div>
      </div>
      <div style="flex:1;text-align:center;background:var(--card);padding:.8rem;border-radius:12px;">
        <div style="font-size:2rem;font-weight:700;color:var(--ok);" id="afterCount">0</div>
        <div style="color:var(--muted);font-size:.85rem;">Tags After</div>
      </div>
      <div style="flex:1;text-align:center;background:var(--card);padding:.8rem;border-radius:12px;">
        <div style="font-size:2rem;font-weight:700;color:var(--danger);" id="removedCount">0</div>
        <div style="color:var(--muted);font-size:.85rem;">Removed</div>
      </div>
    </div>
    <div class="compare-grid">
      <div class="compare-col">
        <h4>&#128994; Before (Original)</h4>
        <div class="compare-box" id="beforeBox"></div>
      </div>
      <div class="compare-col">
        <h4>&#9989;&#65039; After (Scrubbed)</h4>
        <div class="compare-box" id="afterBox"></div>
      </div>
    </div>
  </section>

</main>

<footer>ImageScrub &mdash;"}

