{"path":"Imagescrub/app.py","content":"#!/usr/bin/env python3
"""ImageScrub — Image Metadata Viewer & Remover (Flask App)"""

import os
import io
import json
from datetime import datetime, timedelta
from flask import Flask, request, render_template, jsonify, send_file, abort

app = Flask(__name__)
app.config["UPLOAD_FOLDER"] = "uploads"
os.makedirs(app.config["UPLOAD_FOLDER"], exist_ok=True)


# ── Helper: EXIF tag classification ────────────────────────────────
CATEGORY_MAP = {
    0x0131: ("Camera", "Exposure Time"),          # ExposureTime
    0x0132: ("Camera", "F-Number"),                # FNumber
    0x0134: ("Image", "Image Description"),        # ImageDescription
    0x8769: (None, None),                          # ExifOffset → handled by piexif
}


def _classify_tag(key):
    """Return a friendly category for an EXIF key."""
    camera_keywords = {
        "ExposureTime", "FNumber", "ISOSpeedRatings", "ShutterSpeedValue",
        "ApertureValue", "BrightnessValue", "Flash", "WhiteBalance",
        "MeteringMode", "ExposureProgram", "ExposureCompensation",
        "MaxApertureValue", "SubjectDistance", "SceneCaptureType",
    }
    location_keywords = {
        "GPSAltitudeRef", "GPSLatitude", "GPSLongitude", "GPSTimeStamp",
        "Date/Time Original" ,  # sometimes grouped here by users but we keep in Time below.
    }
    time_keywords = {
        "DateTimeOriginal", "DateTimeDigitized", "OffsetTimeOrigin",
    }
    software_keywords = {
        "Software", "Artist", "Copyright", "ImageUniqueID",
        "Make", "Model",
    }
    if key in camera_keywords:
        return "Camera Settings"
    elif key in location_keywords:
        return "Location (GPS)"
    elif key in time_keywords:
        return "Date & Time"
    elif key in software_keywords:
        return "Software & Author"
    else:
        return "Other Metadata"


def _read_exif_groups(image_bytes):
    """Read EXIF data and group tags into categories."""
    import piexif

    try:
        exif_dict = piexif.load(image_bytes)
    except Exception as e:
        raise ValueError(f"Failed to read EXIF data: {e}")

    groups = {}  # category → list of {name, value}

    for ifd_name in ("0th", "Exif", "1st"):          # standard IFDs
        if ifd_name not in exif_dict or not exif_dict[ifd_name]:
            continue
        for tag_id, raw_value in exif_dict[ifd_name].items():
            tag_name = piexif.TAGS.get(ifd_name, {}).get(tag_id, ("Unknown", 0))[0]
            try:
                decoded = piexif.helper.ExifIFDRational.ratio_to_float(raw_value) if isinstance(raw_value, tuple) else raw_value.decode("utf-8") if isinstance(raw_value, bytes) else str(raw_value)
            except Exception:
                decoded = str(raw_value)

            category = _classify_tag(tag_name.split("/")[-1].strip())  # strip IFD prefix
            groups.setdefault(category, []).append({"name": tag_name, "value": decoded})

    # GPS IFD handled separately (it's a list in piexif v1)
    if exif_dict.get("GPS") and isinstance(exif_dict["GPS"], dict):
        for tag_id, raw_value in exif_dict["GPS"].items():
            try:
                decoded = piexif.helper.ExifIFDRational.ratio_to_float(raw_value) if isinstance(raw_value, tuple) else raw_value.decode("utf-8") if isinstance(raw_value, bytes) else str(raw_value)
            except Exception:
                decoded = str(raw_value)
            groups.setdefault("Location (GPS)", []).append({
                "name": f"GPS ({piexif.TAGS['GPS'].get(tag_id, ('Unknown',0))[0]})",
                "value": decoded,
            })

    # UserComment IFD (sometimes holds text blocks)
    for ifd_name in ("UserComments",):
        if ifd_name not in exif_dict or not exif_dict[ifd_name]:
            continue
        for tag_id, raw_value in exif_dict[ifd_name].items():
            try:
                decoded = piexif.helper.ExifIFDRational.ratio_to_float(raw_value) if isinstance(raw_value, tuple) else raw_value.decode("utf-8") if isinstance(raw_value, bytes) else str(raw_value)
            except Exception:
                decoded = str(raw_value)
            groups.setdefault("User Comments", []).append({"name": tag_id, "value": decoded})

    return groups


# ── Routes ───────────────────────────────────────────────────────────@app.route("/")
def index():
    """Serve the main page."""
    return render_template("index.html")


@app.route("/api/upload", methods=["POST"])
def upload_image():
    """Accept an image, read EXIF and return structured metadata."""
    if "file" not in request.files:
        abort(400, description="No file part")

    f = request.files["file"]
    if not f.filename or "." not in f.filename.lower():
        abort(400, description="Invalid filename")

    raw_bytes = f.read()

    # Validate it's actually an image (Pillow open)
    from PIL import Image as PImage
    try:
        img = PImage.open(io.BytesIO(raw_bytes))
        fmt = img.format or "Unknown"
        width, height = img.size
    except Exception:
        abort(400, description="Cannot decode image")

    if fmt not in ("JPEG", "PNG", "TIFF"):  # piexif supports these natively; WebP handled separately later.
        return jsonify({
            "status": "no_exif_support_yet",
            "format": fmt,
            "message": f"Format '{fmt}' is not fully supported for metadata editing yet.",
            "width": width,
            "height": height,
        })

    # Read EXIF groups
    try:
        exif_groups = _read_exif_groups(raw_bytes)
    except ValueError as e:
        abort(400, description=str(e))

    total_tags = sum(len(v) for v in exif_groups.values())

    return jsonify({
        "status": "ok",
        "format": fmt,
        "width": width,
        "height": height,
        "has_exif": bool(exif_groups),
        "total_tags": total_tags,
        "groups": exif_groups,
    })


@app.route("/api/strip_all", methods=["POST"])
def strip_all():
    """Strip all EXIF and return cleaned image as download."""
    import piexif

    if "file" not in request.files:
        abort(400)
    f = request.files["file"]
    raw_bytes = f.read()

    try:
        # Remove EXIF from JPEG / TIFF
        clean_bytes = piexif.remove(raw_bytes)
    except Exception as e:
        abort(500, description=f"Strip failed: {e}")

    ext_map = {"jpeg": "jpg", "png": "png"}  # add more if needed
    base_ext = os.path.splitext(f.filename.lower())[1].lstrip(".") or "jpg"
    safe_name = f"clean_{f.filename}"
    return send_file(
        io.BytesIO(clean_bytes),
        mimetype=f"image/{base_ext}",
        as_attachment=True,
        download_name=safe_name,
    )


@app.route("/api/strip_selected", methods=["POST"])
def strip_selected():
    """Strip selected categories / tags and return cleaned image."""
    import piexif

    if "file" not in request.files:
        abort(400)

    f = request.files["file"]
    raw_bytes = f.read()

    # Expected JSON body with {"categories": [...], "tags": [...] }
    data = request.get_json(silent=True) or {}
    categories_to_remove = set(data.get("categories", []))
    tag_names_to_remove = set(data.get("tags", []))  # individual tag names

    try:
        exif_dict = piexif.load(raw_bytes)
    except Exception as e:
        abort(500, description=f"Failed to load EXIF: {e}")

    for ifd_name in list(exif_dict.keys()):
        if not isinstance(exif_dict[ifd_name], dict):
            continue          # skip non-dict IFDs (GPS is a list/dict depending on piexif version)

        tags_to_del = []
        for tag_id, _val in exif_dict[ifd_name].items():
            tag_label = piexif.TAGS.get(ifd_name, {}).get(tag_id, ("Unknown", 0))[0]
            category = _classify_tag(tag_label.split("/")[-1].strip())

            if category in categories_to_remove or tag_label in tag_names_to_remove:
                tags_to_del.append(tag_id)

        for tid in tags_to_del:
            del exif_dict[ifd_name][tid]

    # Also clear GPS IFD entirely if "Location (GPS)" is selected.
    if "Location (GPS)" in categories_to_remove and isinstance(exif_dict.get("GPS"), dict):
        exif_dict["GPS"] = {}

    try:
        new_bytes = piexif.dump(raw_bytes, exif_dict)
    except Exception as e:
        abort(500, description=f"Dump failed: {e}")

    base_ext = os.path.splitext(f.filename.lower())[1].lstrip(".") or "jpg"
    safe_name = f"scrubbed_{f.filename}"
    return send_file(
        io.BytesIO(new_bytes),
        mimetype=f"image/{base_ext}",
        as_attachment=True,
        download_name=safe_name,
    )


